[
  {
    "biasType": "Opinion Statements Presented as Fact",
    "biasedText": "\"No matter the content of her story, women are considered unreliable narrators of their own experiences.\"",
    "explanation": "This is an absolute statement that is presented as a universal truth, lacking qualification or acknowledgement of nuance, and does not attribute this sweeping observation to a specific source or data."
  },
  {
    "biasType": "Sensationalism/Emotionalism",
    "biasedText": "\"The highly publicized Amber Heard and Johnny Depp civil case showed in real time how women’s testimony can be discounted in the courtroom and men found to be more credible even though statistically men are more likely to lie than women.\"",
    "explanation": "The connection to a notorious celebrity case is used to create an emotional reaction and bolster the article’s thesis, even though that specific case is highly contested and complex, making it a poor representative of the general principle."
  },
  {
    "biasType": "Omission of Source Attribution",
    "biasedText": "\"Laws meant to protect women and deter further abuse often fail to achieve their purpose, because women telling stories of abuse by their male partners are simply not believed.\"",
    "explanation": "The claim is not directly attributed to a named study, expert, or report, making it hard for readers to assess its basis or determine the expertise behind the statement."
  },
  {
    "biasType": "Subjective Qualifying Adjectives",
    "biasedText": "\"an unprecedented wave of testimonials about the serious harms women all too frequently endure in the justice system\"",
    "explanation": "Phrases like 'unprecedented wave' and 'serious harms all too frequently' inject subjective qualifiers that influence readers' perception without offering concrete measurements or comparison points."
  },
  {
    "biasType": "Slant",
    "biasedText": "\"...how women are routinely disbelieved as they try to tell their stories to employers, police, Human Resource personnel.\"",
    "explanation": "The article presents the perspective that women’s testimonies are universally disbelieved as a norm, without adequately addressing any counterpoints, exceptions, or complexity in the data."
  }
]

